'use server';

import { createClient, createAdminClient } from '@/lib/supabase/server';
import { revalidatePath } from 'next/cache';
import { 
  AdminSearchProfile, 
  Profile, 
  SupportTicket, 
  AdminLedgerEntry,
  UserStatus,
  FullUserDetails,
  SupportTicketWithProfile,
  AdminLedgerEntryWithProfile,
  AccountPurchase,
  AccountTier,
  ChallengeEntry,
  ChallengeRound,
  Referral,
  PlatformSettings
} from '@/types';

/**
 * Verify if the current user is an admin.
 * Use this inside every admin-only server action.
 * Standard client is used here to check the authenticated user's profile.
 */
export async function verifyAdmin() {
  const supabase = await createClient();
  const adminClient = await createAdminClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) throw new Error('Unauthorized');

  // Use Admin Client to bypass RLS recursion when verifying admin role
  const { data: profile } = await adminClient
    .from('profiles')
    .select('role')
    .eq('id', user.id)
    .single();

  // PRODUCTION SAFETY GATING:
  const hasAdminRole = profile?.role === 'admin';

  if (hasAdminRole) {
    return user;
  }

  throw new Error('Forbidden: Admin access only.');
}

// ─────────────────────────────────────────────────────────────────────────────
// 1. USER MANAGEMENT
// ─────────────────────────────────────────────────────────────────────────────

export async function searchUsers(query: string): Promise<AdminSearchProfile[]> {
  await verifyAdmin();
  const supabase = await createAdminClient();

  let q = supabase.from('profiles').select('*, wallets(balance_ngn)');

  if (query) {
    q = q.or(`username.ilike.%${query}%,full_name.ilike.%${query}%,phone.ilike.%${query}%,email.ilike.%${query}%,id.eq.${query}`);
  }

  const { data, error } = await q.limit(50);
  if (error) throw error;
  return data as AdminSearchProfile[];
}

export async function getUserDetails(userId: string): Promise<FullUserDetails> {
  await verifyAdmin();
  const supabase = await createAdminClient();

  const [profile, wallet, purchases, entries, referrals] = await Promise.all([
    supabase.from('profiles').select('*').eq('id', userId).single(),
    supabase.from('wallets').select('*').eq('user_id', userId).single(),
    supabase.from('account_purchases').select('*, account_tiers(*)').eq('user_id', userId),
    supabase.from('challenge_entries').select('*, challenge_rounds(*), account_tiers(*)').eq('user_id', userId),
    supabase.from('referrals').select('*, profiles!referrals_referred_user_id_fkey(username)').eq('referrer_id', userId)
  ]);

  return {
    profile: profile.data,
    wallet: wallet.data,
    purchases: (purchases.data || []) as (AccountPurchase & { account_tiers: AccountTier | null })[], 
    entries: (entries.data || []) as (ChallengeEntry & { challenge_rounds: ChallengeRound | null, account_tiers: AccountTier | null })[],
    referrals: (referrals.data || []) as (Referral & { profiles: { username: string } | null })[]
  };
}

export async function updateUserStatus(userId: string, updates: { 
  status?: UserStatus; 
  is_verified?: boolean; 
  is_suspended?: boolean; 
  is_demo?: boolean;
  admin_notes?: string;
  phone_verified?: boolean;
}) {
  const admin = await verifyAdmin();
  const supabase = await createAdminClient();

  const { error } = await supabase
    .from('profiles')
    .update(updates)
    .eq('id', userId);

  if (error) throw error;

  // Audit log
  await supabase.from('admin_audit_logs').insert({
    admin_id: admin.id,
    action: 'update_user_status',
    target_user_id: userId,
    details: updates
  });

  revalidatePath('/admin');
  return { success: true };
}

export async function createDemoUser(data: { 
  email: string; 
  username: string; 
  password?: string;
  balance: number;
  tierId?: string;
}) {
  const admin = await verifyAdmin();
  const supabase = await createAdminClient();

  // 1. Create User via Admin Auth
  const { data: authUser, error: authError } = await supabase.auth.admin.createUser({
    email: data.email,
    password: data.password || 'DemoPassword123!', // Custom or standard demo password
    email_confirm: true,
    user_metadata: { 
      full_name: `Demo: ${data.username}`,
      username: data.username,
      is_demo: true 
    }
  });

  if (authError) throw authError;

  // 2. Profile record is likely created via trigger, but we update it to ensure demo status
  const { error: profileError } = await supabase
    .from('profiles')
    .update({ 
      is_demo: true, 
      status: 'demo',
      is_verified: true 
    })
    .eq('id', authUser.user.id);

  if (profileError) throw profileError;

  // 3. Fund Wallet
  const { data: wallet } = await supabase.from('wallets').select('id').eq('user_id', authUser.user.id).single();
  if (wallet) {
    await supabase.from('wallets').update({ balance_ngn: data.balance }).eq('id', wallet.id);
    await supabase.from('wallet_transactions').insert({
      wallet_id: wallet.id,
      amount: data.balance,
      type: 'reward',
      reference: 'demo_initial_funding'
    });
  }

  // 4. Enroll in Active Round if tier provided
  if (data.tierId) {
    const { data: activeRound } = await supabase.from('challenge_rounds').select('id').eq('status', 'active').maybeSingle();
    if (activeRound) {
      await supabase.from('challenge_entries').insert({
        user_id: authUser.user.id,
        round_id: activeRound.id,
        tier_id: data.tierId,
        streak_count: 0
      });
    }
  }

  // Audit
  await supabase.from('admin_audit_logs').insert({
    admin_id: admin.id,
    action: 'create_demo_user',
    target_user_id: authUser.user.id,
    details: data
  });

  revalidatePath('/admin');
  return { success: true, userId: authUser.user.id };
}

// ─────────────────────────────────────────────────────────────────────────────
// 2. FINANCIAL & LEDGER
// ─────────────────────────────────────────────────────────────────────────────

export async function adjustUserWallet(userId: string, amount: number, reason: string) {
  const admin = await verifyAdmin();
  const supabase = await createAdminClient();

  const { error } = await supabase.rpc('adjust_user_wallet_admin', {
    p_admin_id: admin.id,
    p_user_id: userId,
    p_amount: amount,
    p_reason: reason
  });

  if (error) throw error;

  revalidatePath('/admin');
  return { success: true };
}

export async function getAdminLedger(limit = 50): Promise<AdminLedgerEntryWithProfile[]> {
  await verifyAdmin();
  const supabase = await createAdminClient();

  const { data, error } = await supabase
    .from('admin_ledger')
    .select('*, profiles!admin_ledger_user_id_fkey(username)')
    .order('created_at', { ascending: false })
    .limit(limit);

  if (error) throw error;
  return data as AdminLedgerEntryWithProfile[];
}

// ─────────────────────────────────────────────────────────────────────────────
// 3. SUPPORT MANAGEMENT
// ─────────────────────────────────────────────────────────────────────────────

export async function getSupportTickets(filters: { status?: string } = {}): Promise<SupportTicketWithProfile[]> {
  await verifyAdmin();
  const supabase = await createAdminClient();

  let q = supabase.from('support_tickets').select('*, profiles(username)');

  if (filters.status && filters.status !== 'all') {
    q = q.eq('status', filters.status);
  }

  const { data, error } = await q.order('created_at', { ascending: false });
  if (error) throw error;
  return data as SupportTicketWithProfile[];
}

export async function updateTicketStatus(ticketId: string, status: string, internalNotes?: string) {
  const admin = await verifyAdmin();
  const supabase = await createAdminClient();

  const updates: Partial<SupportTicket> & { updated_at?: string } = { status: status as any, updated_at: new Date().toISOString() };
  if (internalNotes !== undefined) updates.internal_notes = internalNotes;

  const { error } = await supabase
    .from('support_tickets')
    .update(updates)
    .eq('id', ticketId);

  if (error) throw error;

  revalidatePath('/admin');
  return { success: true };
}

// ─────────────────────────────────────────────────────────────────────────────
// 4. PLATFORM CONTROLS
// ─────────────────────────────────────────────────────────────────────────────

export async function updatePlatformSettings<K extends keyof PlatformSettings>(key: K, value: PlatformSettings[K]) {
  const admin = await verifyAdmin();
  const supabase = await createAdminClient();

  const { error } = await supabase
    .from('platform_settings')
    .upsert({ key, value, updated_at: new Date().toISOString() });

  if (error) throw error;

  // Audit log
  await supabase.from('admin_audit_logs').insert({
    admin_id: admin.id,
    action: 'update_platform_settings',
    details: { key, value }
  });

  revalidatePath('/admin');
  return { success: true };
}

export async function getAllPlatformSettings(): Promise<Partial<PlatformSettings>> {
  await verifyAdmin();
  const supabase = await createAdminClient();

  const { data, error } = await supabase.from('platform_settings').select('*');
  if (error) throw error;
  
  return data.reduce((acc: Partial<PlatformSettings>, curr) => {
    acc[curr.key as keyof PlatformSettings] = curr.value as any;
    return acc;
  }, {});
}

export async function getPlatformMetrics() {
  await verifyAdmin();
  const supabase = await createAdminClient();

  // Active Challengers (Real users only)
  const { count: realUsers } = await supabase
    .from('profiles')
    .select('*', { count: 'exact', head: true })
    .eq('is_demo', false);

  // Revenue
  const { data: revenueData } = await supabase
    .from('account_purchases')
    .select('amount_paid');
  const revenue = revenueData?.reduce((sum, p) => sum + p.amount_paid, 0) || 0;

  // Payouts
  const { data: payoutData } = await supabase
    .from('payout_requests')
    .select('amount')
    .eq('status', 'completed');
  const payouts = payoutData?.reduce((sum, p) => sum + p.amount, 0) || 0;

  // Support health
  const { count: openTickets } = await supabase
    .from('support_tickets')
    .select('*', { count: 'exact', head: true })
    .eq('status', 'open');

  return {
    realUsers: realUsers || 0,
    revenue,
    payouts,
    openTickets: openTickets || 0
  };
}

export async function revalidatePlatform() {
  await verifyAdmin();
  revalidatePath('/admin', 'layout');
  revalidatePath('/dashboard', 'layout');
  revalidatePath('/', 'layout');
  return { success: true };
}

// ─────────────────────────────────────────────────────────────────────────────
// 5. PREDICTIONS & PLAYS
// ─────────────────────────────────────────────────────────────────────────────

export async function getPredictionsOverview(filters: { round_id?: string; limit?: number } = {}) {
  await verifyAdmin();
  const supabase = await createAdminClient();

  let q = supabase
    .from('challenge_entries')
    .select(`
      id,
      user_id,
      round_id,
      tier_id,
      streak_count,
      is_winner,
      created_at,
      profiles(username, email),
      challenge_rounds(round_number),
      account_tiers(name),
      predictions(
        id,
        match_id,
        prediction,
        is_correct,
        is_locked,
        challenge_matches(home_team, away_team, kickoff_time, status, home_score, away_score)
      )
    `);

  if (filters.round_id && filters.round_id !== 'all') {
    q = q.eq('round_id', filters.round_id);
  }

  const { data, error } = await q
    .order('created_at', { ascending: false })
    .limit(filters.limit || 100);

  if (error) throw error;
  return data;
}

export async function undoMatchSettlement(matchId: string) {
  const admin = await verifyAdmin();
  const adminClient = await createAdminClient();

  // 1. Reset match status
  const { error: matchError } = await adminClient
    .from('challenge_matches')
    .update({ status: 'live', home_score: 0, away_score: 0 })
    .eq('id', matchId);

  if (matchError) throw matchError;

  // 2. Unlock all predictions for this match so they can be re-settled
  const { error: predError } = await adminClient
    .from('predictions')
    .update({ is_locked: false, is_correct: null })
    .eq('match_id', matchId);

  if (predError) throw predError;

  // Audit
  await adminClient.from('admin_audit_logs').insert({
    admin_id: admin.id,
    action: 'undo_match_settlement',
    target_user_id: null,
    details: { matchId }
  });

  revalidatePath('/admin');
  return { success: true };
}

/**
 * HYBRID ENGINE: Force update a match score and re-run settlement logic only for this match.
 * Unlike undoMatchSettlement, this works even on 'finished' matches to "fix" a desired score.
 */
export async function overrideMatchScore(matchId: string, homeScore: number, awayScore: number) {
  const admin = await verifyAdmin();
  const adminClient = await createAdminClient();

  // 1. Update the match score and status
  const { error: matchError } = await adminClient
    .from('challenge_matches')
    .update({ 
      home_score: homeScore, 
      away_score: awayScore, 
      status: 'finished' 
    })
    .eq('id', matchId);

  if (matchError) throw matchError;

  // 2. We don't automatically re-payout (that's dangerous), but we update prediction 'is_correct' flags
  const { data: predictions } = await adminClient
    .from('predictions')
    .select('id, entry_id, prediction')
    .eq('match_id', matchId);

  if (predictions) {
    const outcome = homeScore > awayScore ? '1' : homeScore < awayScore ? '2' : 'X';
    
    for (const pred of predictions) {
      await adminClient
        .from('predictions')
        .update({ 
          is_correct: pred.prediction === outcome,
          is_locked: true 
        })
        .eq('id', pred.id);
    }
  }

  // 3. Audit
  await adminClient.from('admin_audit_logs').insert({
    admin_id: admin.id,
    action: 'override_match_score',
    details: { matchId, homeScore, awayScore }
  });

  revalidatePath('/admin');
  return { success: true };
}

'use client';

import { useState } from 'react';
import { 
  Monitor, 
  Users, 
  BarChart3, 
  Sword, 
  HelpCircle, 
  Settings, 
  Shield, 
  Zap, 
  Activity,
  ChevronRight,
  Database,
  Cpu,
  Menu,
  X,
  LayoutDashboard
} from 'lucide-react';
import { ChallengeRound, ChallengeMatch, PayoutRequest, Transaction } from '@/types';

// Import Modular Views
import DashboardView from './views/DashboardView';
import UsersView from './views/UsersView';
import FinanceView from './views/FinanceView';
import MatchesView from './views/MatchesView';
import SupportView from './views/SupportView';
import SettingsView from './views/SettingsView';

interface AdminClientProps {
  initialMetrics: { totalUsers: number; totalRevenue: number; pendingPayouts: number };
  rounds: ChallengeRound[];
  matches: (ChallengeMatch & { challenge_rounds?: { round_number: number } })[];
  recentPurchases: (Transaction & { profiles?: { username: string } })[];
  payoutRequests: (PayoutRequest & { profiles?: { username: string } })[];
}

export default function AdminClient({
  initialMetrics,
  rounds,
  matches,
  recentPurchases,
  payoutRequests
}: AdminClientProps) {
  const [activeView, setActiveView] = useState<'dashboard'|'users'|'finance'|'matches'|'support'|'settings'>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const navItems = [
    { id: 'dashboard' as const, label: 'Overview', icon: LayoutDashboard },
    { id: 'users' as const, label: 'Users', icon: Users },
    { id: 'finance' as const, label: 'Finance', icon: BarChart3 },
    { id: 'matches' as const, label: 'Matches', icon: Sword },
    { id: 'support' as const, label: 'Support', icon: HelpCircle },
    { id: 'settings' as const, label: 'Settings', icon: Settings },
  ];

  const activeLabel = navItems.find(i => i.id === activeView)?.label;

  return (
    <div className="min-h-screen bg-primary text-white flex overflow-x-hidden">
      
      {/* ─── MOBILE DRAWER OVERLAY ─── */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[60] lg:hidden animate-fade-in"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* ─── COMPACT SIDE NAVIGATION ─── */}
      <aside className={`
        fixed inset-y-0 left-0 w-72 border-r border-white/5 bg-[#05070a]/90 backdrop-blur-3xl z-[70] 
        transition-transform duration-300 ease-in-out lg:translate-x-0 lg:static lg:h-screen
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        flex flex-col p-6 shadow-2xl
      `}>
        <div className="mb-12 px-3 flex items-center justify-between">
          <div>
            <div className="flex items-center gap-8 mb-4">
               <Shield className="w-6 h-6 text-gold opacity-80" />
               <div className="text-[9px] font-black text-gold uppercase tracking-[0.2em]">Matrix Control</div>
            </div>
            <h1 className="font-display text-xl font-black tracking-tighter uppercase whitespace-nowrap">Predchain Admin</h1>
          </div>
          <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-muted p-4"><X size={20} /></button>
        </div>

        <nav className="flex-1 flex flex-col gap-3">
          {navItems.map(item => (
            <button 
              key={item.id}
              onClick={() => {
                setActiveView(item.id);
                setIsSidebarOpen(false);
              }}
              className={`flex items-center justify-between p-12 px-16 rounded-2xl transition-all font-black uppercase text-[10px] tracking-widest group ${
                activeView === item.id 
                  ? 'bg-white/5 text-white border border-white/10 shadow-lg' 
                  : 'text-muted hover:text-white hover:bg-white/5 border border-transparent'
              }`}
            >
              <div className="flex items-center gap-12">
                 <item.icon className={`w-4 h-4 transition-opacity ${activeView === item.id ? 'opacity-100 text-blue-electric' : 'opacity-40 group-hover:opacity-70'}`} />
                 {item.label}
              </div>
              {item.id === 'finance' && initialMetrics.pendingPayouts > 0 && (
                <div className="w-1.5 h-1.5 rounded-full bg-danger shadow-[0_0_8px_var(--danger)]" />
              )}
            </button>
          ))}
        </nav>

        <div className="mt-auto p-16 bg-white/5 border border-white/10 rounded-2xl">
          <div className="flex items-center gap-12">
            <div className="w-32 h-32 rounded-lg bg-grad-gold flex items-center justify-center font-black text-black text-[10px]">AD</div>
            <div className="flex flex-col">
              <div className="text-[10px] font-black text-white leading-none mb-2 text-gold">SUPERUSER</div>
              <div className="flex items-center gap-4">
                 <div className="w-4 h-4 rounded-full bg-success opacity-80" />
                 <div className="text-[8px] text-muted font-bold uppercase tracking-widest">Active Node</div>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* ─── MAIN CONTENT AREA ─── */}
      <main className="flex-1 min-w-0 p-12 lg:p-24 max-w-[1500px] mx-auto w-full">
        
        {/* Header Section */}
        <header className="mb-12 flex justify-between items-center lg:items-end">
          <div className="flex items-center gap-12 lg:block">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-10 bg-white/5 rounded-xl text-muted hover:text-white transition-all transform active:scale-95">
               <Menu size={20} />
            </button>
            
            <div className="animate-fade-in">
              <div className="flex items-center gap-8 mb-8 opacity-40 hidden lg:flex">
                 <span className="text-[10px] font-bold uppercase tracking-widest">Sentinel</span>
                 <ChevronRight className="w-10 h-10" />
                 <span className="text-[10px] font-bold uppercase tracking-widest">{activeLabel}</span>
              </div>
              <h2 className="font-display text-2xl lg:text-3xl font-black tracking-tight mb-2 lg:mb-4">
                {activeLabel}
              </h2>
              <p className="text-muted text-[8px] lg:text-[10px] font-bold uppercase tracking-[0.2em] whitespace-nowrap">
                Oversight & Verification Protocols
              </p>
            </div>
          </div>

          <div className="flex gap-24 items-center">
             <div className="flex flex-col items-end">
                <div className="text-[7px] lg:text-[9px] text-muted font-black tracking-widest uppercase mb-2">Network Health</div>
                <div className="flex items-center gap-6">
                   <Activity className="w-10 h-10 lg:w-12 h-12 text-success opacity-60" />
                   <span className="text-success font-mono text-[10px] lg:text-xs font-bold uppercase tracking-widest">Encrypted</span>
                </div>
             </div>
          </div>
        </header>

        {/* View Switcher with Slide Animation */}
        <div className="animate-slide-up">
          {activeView === 'dashboard' && (
            <DashboardView metrics={initialMetrics} recentPurchases={recentPurchases} />
          )}
          {activeView === 'users' && (
            <UsersView />
          )}
          {activeView === 'finance' && (
            <FinanceView payoutRequests={payoutRequests} initialMetrics={initialMetrics} />
          )}
          {activeView === 'matches' && (
            <MatchesView matches={matches} rounds={rounds} />
          )}
          {activeView === 'support' && (
            <SupportView />
          )}
          {activeView === 'settings' && (
            <SettingsView />
          )}
        </div>

      </main>
    </div>
  );
}

import { createClient } from '@/lib/supabase/server';
import { redirect } from 'next/navigation';
import AdminClient from './admin-client';

export default async function AdminPage() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) {
    redirect('/login');
  }

  const { data: profile } = await supabase
    .from('profiles')
    .select('role')
    .eq('id', user.id)
    .single();

  if (profile?.role !== 'admin' && user.email !== 'olabodesamuel0920@gmail.com') {
    redirect('/dashboard');
  }

  // Fetch Admin Data
  const { count: userCount } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
  const { data: recentPurchases } = await supabase.from('account_purchases').select('amount:amount_paid, created_at, profiles(username, full_name)').order('created_at', { ascending: false }).limit(5);
  const { data: activeRounds } = await supabase.from('challenge_rounds').select('*').order('round_number', { ascending: false });
  const { data: pendingPayouts } = await supabase.from('payout_requests').select('*, profiles(username)').eq('status', 'pending');
  const { data: allMatches } = await supabase.from('challenge_matches').select('*, challenge_rounds!round_id(round_number)').order('kickoff_time', { ascending: false });

  // Revenue calculation
  const { data: purchases } = await supabase.from('account_purchases').select('amount_paid');
  const totalRevenue = purchases?.reduce((acc, curr) => acc + curr.amount_paid, 0) || 0;

  return (
    <AdminClient 
      initialMetrics={{
        totalUsers: userCount || 0,
        totalRevenue: totalRevenue,
        pendingPayouts: pendingPayouts?.length || 0
      }}
      rounds={activeRounds || []}
      matches={allMatches || []}
      recentPurchases={(recentPurchases || []) as any[]}
      payoutRequests={pendingPayouts || []}
    />
  );
}

