'use client';

import { useState, useEffect, useTransition } from 'react';
import { 
  Wallet, 
  TrendingUp, 
  AlertCircle, 
  Clock, 
  ArrowUpRight, 
  ArrowDownLeft, 
  CheckCircle2, 
  XCircle, 
  Banknote, 
  ShieldCheck, 
  Activity,
  ChevronRight,
  ShieldAlert,
  Check
} from 'lucide-react';
import { approvePayout, rejectPayout } from '@/app/actions/wallet';
import { getAdminLedger } from '@/app/actions/admin';
import { PayoutRequest, AdminLedgerEntryWithProfile } from '@/types';

interface FinanceViewProps {
  payoutRequests: (PayoutRequest & { profiles?: { username: string } })[];
  initialMetrics: { totalRevenue: number; pendingPayouts: number };
}

export default function FinanceView({ payoutRequests, initialMetrics }: FinanceViewProps) {
  const [isPending, startTransition] = useTransition();
  const [rejectionReason, setRejectionReason] = useState<Record<string, string>>({});
  const [isRejecting, setIsRejecting] = useState<string | null>(null);
  const [ledger, setLedger] = useState<AdminLedgerEntryWithProfile[]>([]);
  const [successMsg, setSuccessMsg] = useState('');
  const [errorMsg, setErrorMsg] = useState('');

  const loadLedger = async () => {
    try {
      const data = await getAdminLedger(20);
      setLedger(data);
    } catch (err) {
      console.error('Failed to load ledger:', err);
    }
  };

  useEffect(() => {
    loadLedger();
  }, []);

  const handleApprove = async (id: string) => {
    startTransition(async () => {
      try {
        await approvePayout(id, 'Approved by Administrator');
        setSuccessMsg('Payout approved successfully.');
        setTimeout(() => setSuccessMsg(''), 3000);
        loadLedger();
      } catch (err: any) {
        setErrorMsg(err.message || 'Approval failed');
      }
    });
  };

  const handleReject = async (id: string) => {
    const reason = rejectionReason[id];
    if (!reason) return;
    
    startTransition(async () => {
      try {
        await rejectPayout(id, reason);
        setIsRejecting(null);
        setSuccessMsg('Payout rejected. Funds restored.');
        setTimeout(() => setSuccessMsg(''), 3000);
        loadLedger();
      } catch (err: any) {
        setErrorMsg(err.message || 'Rejection failed');
      }
    });
  };

  return (
    <div className="flex flex-col gap-24 animate-slide-up">
      {/* Toast Notifications */}
      {(successMsg || errorMsg) && (
        <div className={`fixed bottom-6 right-6 z-[100] px-5 py-3 rounded-xl backdrop-blur-xl border flex items-center gap-3 shadow-2xl animate-slide-up ${
          successMsg ? 'bg-success/90 border-success/20 text-black' : 'bg-danger/90 border-danger/20 text-white'
        }`}>
           {successMsg ? <Check className="w-4 h-4" /> : <AlertCircle className="w-4 h-4" />}
           <span className="text-xs font-bold">{successMsg || errorMsg}</span>
        </div>
      )}

      {/* ─── KPI GRID ─── */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="card p-6 bg-white/[0.02]">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-blue-electric/10 rounded-lg"><TrendingUp className="w-4 h-4 text-blue-electric" /></div>
            <span className="text-[9px] text-muted font-black uppercase tracking-widest">Total Revenue</span>
          </div>
          <div className="font-display text-2xl font-black text-white">₦{initialMetrics.totalRevenue.toLocaleString()}</div>
          <div className="text-[9px] text-muted/40 mt-3 font-mono uppercase tracking-widest">Total revenue</div>
        </div>

        <div className="card p-6 bg-white/[0.02]">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-blue-electric/10 rounded-lg"><Wallet className="w-4 h-4 text-blue-electric" /></div>
            <span className="text-[9px] text-muted font-black uppercase tracking-widest">Payout Volume</span>
          </div>
          <div className="font-display text-2xl font-black text-blue-electric">₦{(payoutRequests.reduce((sum, r) => sum + r.amount, 0)).toLocaleString()}</div>
          <div className="text-[9px] text-muted/40 mt-3 font-mono uppercase tracking-widest">Pending distributions</div>
        </div>

        <div className={`card p-6 transition-all ${initialMetrics.pendingPayouts > 0 ? 'bg-danger/[0.02] border-danger/20 shadow-[0_0_20px_rgba(255,23,68,0.05)]' : 'bg-white/[0.02]'}`}>
          <div className="flex justify-between items-start mb-4">
            <div className={`p-2 rounded-lg ${initialMetrics.pendingPayouts > 0 ? 'bg-danger/10' : 'bg-white/5'}`}>
               <ShieldAlert className={`w-4 h-4 ${initialMetrics.pendingPayouts > 0 ? 'text-danger' : 'text-muted opacity-40'}`} />
            </div>
            <span className={`text-[9px] font-black uppercase tracking-widest ${initialMetrics.pendingPayouts > 0 ? 'text-danger' : 'text-muted'}`}>Pending Requests</span>
          </div>
          <div className="font-display text-2xl font-black text-danger">{initialMetrics.pendingPayouts}</div>
          <div className="text-[9px] text-muted/40 mt-3 font-mono uppercase tracking-widest">Awaiting Verification</div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* ─── PAYOUT REQUESTS ─── */}
        <div className="card p-0 flex flex-col overflow-hidden">
          <div className="p-20 border-b border-white/5 flex justify-between items-center bg-white/[0.01]">
             <div className="flex items-center gap-10">
                <Clock className="w-5 h-5 text-blue-electric opacity-60" />
                <h3 className="font-display text-sm font-black uppercase tracking-widest">Payout Requests</h3>
             </div>
             <div className="flex items-center gap-12 font-mono text-[9px] font-black text-muted opacity-60">
                <span className="flex items-center gap-6"><div className="w-4 h-4 rounded-full bg-danger opacity-40" /> AWAITING APPROVAL</span>
             </div>
          </div>
          
          <div className="p-4 flex flex-col gap-4">
            {payoutRequests.length === 0 ? (
              <div className="text-center py-48 flex flex-col items-center gap-4 opacity-30">
                 <ShieldCheck className="w-10 h-10 text-muted" />
                 <p className="text-[10px] uppercase font-black tracking-widest italic font-mono">No pending payout requests.</p>
              </div>
            ) : (
              payoutRequests.map(r => (
                <div key={r.id} className={`card p-16 transition-all border outline-none ${
                    r.is_flagged 
                    ? 'border-danger/30 bg-danger/[0.03] shadow-lg shadow-danger/5' 
                    : 'border-white/5 bg-white/[0.02] hover:border-white/10'
                  }`}
                >
                  <div className="flex justify-between items-center mb-16">
                    <div className="flex items-center gap-12">
                      <div className="w-24 h-24 rounded-lg bg-blue-electric/10 border border-blue-electric/20 flex items-center justify-center font-black text-[10px] text-blue-electric font-display uppercase">
                         {r.profiles?.username?.[0] || 'U'}
                      </div>
                      <div>
                        <div className="flex items-center gap-8 mb-1">
                           <span className="font-black text-sm text-white">@{r.profiles?.username}</span>
                           {r.is_flagged && <span className="badge badge-danger text-[7px] font-black uppercase px-6">Risk: {r.flagging_reason}</span>}
                        </div>
                        <div className="text-[9px] text-muted font-mono uppercase tracking-tighter opacity-60 flex items-center gap-6">
                           ID: {r.id.split('-')[0]} <ChevronRight className="w-3 h-3" /> {r.id.split('-').pop()}
                        </div>
                      </div>
                    </div>
                    <div className="text-right">
                       <span className="text-xl font-black text-white font-display">₦{r.amount.toLocaleString()}</span>
                    </div>
                  </div>
                  
                  <div className="p-12 bg-white/[0.03] rounded-xl mb-16 border border-white/5 flex gap-12">
                    <div className="p-8 bg-white/5 rounded-lg h-fit"><Banknote className="w-5 h-5 text-muted opacity-40" /></div>
                    <div className="flex-1">
                       <div className="text-[8px] text-muted uppercase font-black mb-4 tracking-widest">Bank Details</div>
                       <div className="flex justify-between items-center">
                          <div className="text-[11px] font-black text-white uppercase">{r.bank_account_info?.bank}</div>
                          <div className="text-[11px] font-mono text-blue-electric font-black tracking-widest">{r.bank_account_info?.account}</div>
                       </div>
                       <div className="text-[9px] text-muted mt-2 font-mono uppercase font-medium">{r.bank_account_info?.name}</div>
                    </div>
                  </div>

                  <div className="flex gap-4">
                    {isRejecting === r.id ? (
                      <div className="flex gap-4 w-full animate-slide-right">
                        <input 
                          type="text" 
                          placeholder="REASON FOR REJECTION..." 
                          value={rejectionReason[r.id] || ''}
                          onChange={(e) => setRejectionReason(prev => ({ ...prev, [r.id]: e.target.value }))}
                          className="input-premium flex-1 py-8 text-[11px] font-medium"
                        />
                        <button onClick={() => handleReject(r.id)} disabled={isPending} className="btn btn-danger btn-xs px-12 font-black uppercase text-[10px]">REJECT</button>
                        <button onClick={() => setIsRejecting(null)} className="p-8 hover:bg-white/5 rounded-lg opacity-40 hover:opacity-100 transition-all font-black">×</button>
                      </div>
                    ) : (
                      <>
                        <button 
                          disabled={isPending}
                          className="btn btn-blue btn-xs flex-1 py-10 font-black uppercase tracking-[0.15em] text-[10px] shadow-lg shadow-blue-electric/20" 
                          onClick={() => handleApprove(r.id)}
                        >
                          <CheckCircle2 className="w-4 h-4 mr-8" />
                          {isPending ? 'Processing...' : 'Approve Payout'}
                        </button>
                        <button 
                          disabled={isPending}
                          className="p-10 px-16 hover:bg-danger/10 text-danger rounded-xl transition-all font-black uppercase tracking-[0.15em] text-[10px] border border-transparent hover:border-danger/20 flex items-center justify-center gap-8" 
                          onClick={() => setIsRejecting(r.id)}
                        >
                          <XCircle className="w-4 h-4" />
                          Reject
                        </button>
                      </>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>

        {/* ─── TRANSACTION LOGS ─── */}
        <div className="card p-0 flex flex-col overflow-hidden h-fit sticky top-24">
           <div className="p-20 border-b border-white/5 flex justify-between items-center bg-white/[0.01]">
              <div className="flex items-center gap-10">
                 <Activity className="w-5 h-5 text-blue-electric opacity-60" />
                 <h3 className="font-display text-sm font-bold uppercase tracking-widest">Transaction Audit</h3>
              </div>
              <div className="badge badge-muted text-[8px] font-black px-8 py-2">System Logs</div>
           </div>
           
           <div className="flex flex-col">
              {ledger.length === 0 ? (
                <p className="text-[10px] text-muted italic opacity-30 py-60 text-center font-mono">No recent transactions recorded.</p>
              ) : (
                ledger.map(entry => (
                  <div key={entry.id} className="p-16 border-b border-white/5 flex justify-between items-center hover:bg-white/[0.02] last:border-0 transition-colors">
                    <div className="flex items-center gap-12">
                       <div className={`p-8 rounded-lg ${entry.type === 'credit' ? 'bg-success/5 border border-success/10' : 'bg-danger/5 border border-danger/10'}`}>
                          {entry.type === 'credit' ? <ArrowDownLeft className={`w-4 h-4 text-success`} /> : <ArrowUpRight className={`w-4 h-4 text-danger`} />}
                       </div>
                       <div>
                          <div className="flex items-center gap-6">
                            <span className="text-[11px] font-black text-white">@{entry.profiles?.username || 'system'}</span>
                            <ChevronRight className="w-3 h-3 text-muted opacity-20" />
                          </div>
                          <div className="text-[9px] text-muted font-bold tracking-widest uppercase opacity-40 mt-1 italic truncate max-w-150">"{(entry.reason || 'Platform Adjustment')}"</div>
                       </div>
                    </div>
                    <div className="text-right flex flex-col items-end gap-2">
                       <div className={`font-black font-display text-sm ${entry.type === 'credit' ? 'text-success' : 'text-danger'}`}>
                         {entry.type === 'credit' ? '+' : '-'} ₦{Math.abs(entry.amount).toLocaleString()}
                       </div>
                       <div className="text-[8px] text-muted font-mono font-bold">{new Date(entry.created_at).toLocaleTimeString()}</div>
                    </div>
                  </div>
                ))
              )}
           </div>
           
             <div className="p-20 bg-white/[0.01] border-t border-white/5">
              <div className="flex items-center gap-12 p-12 bg-blue-electric/5 border border-blue-electric/10 rounded-xl relative overflow-hidden group">
                 <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:opacity-20 transition-opacity"><ShieldCheck className="w-12 h-12" /></div>
                 <div className="p-8 bg-blue-electric/10 rounded-lg"><ShieldCheck className="w-5 h-5 text-blue-electric" /></div>
                 <div className="relative z-10">
                    <h4 className="text-[9px] font-black text-white uppercase tracking-widest mb-2">Platform Integrity</h4>
                    <p className="text-[10px] text-muted leading-relaxed font-medium">All platform transactions are verified and logged for complete audit transparency.</p>
                 </div>
              </div>
            </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useTransition } from 'react';
import { 
  Sword, 
  Calendar, 
  TrendingUp, 
  CheckCircle2, 
  Activity, 
  Trophy, 
  ShieldCheck, 
  AlertCircle, 
  Settings2,
  ChevronRight,
  Play,
  RotateCcw,
  Check,
  Plus
} from 'lucide-react';
import { settleMatchResult, updateMatchStatus, updateRoundStatus, createMatch } from '@/app/actions/predictions';
import { ChallengeMatch, ChallengeRound } from '@/types';

interface MatchesViewProps {
  matches: (ChallengeMatch & { challenge_rounds?: { round_number: number } })[];
  rounds: ChallengeRound[];
}

export default function MatchesView({ matches, rounds }: MatchesViewProps) {
  const [isPending, startTransition] = useTransition();
  const [editingScores, setEditingScores] = useState<Record<string, { home: number; away: number }>>({});
  const [selectedRoundId, setSelectedRoundId] = useState<string>(rounds.find(r => r.status === 'active')?.id || rounds[0]?.id || '');
  const [successMsg, setSuccessMsg] = useState('');
  const [errorMsg, setErrorMsg] = useState('');
  const [showMatchModal, setShowMatchModal] = useState(false);
  const [matchData, setMatchData] = useState({ home_team: '', away_team: '', kickoff_time: '' });

  const filteredMatches = matches.filter(m => m.round_id === selectedRoundId);
  const selectedRound = rounds.find(r => r.id === selectedRoundId);

  const handleScoreChange = (matchId: string, side: 'home' | 'away', val: number) => {
    setEditingScores(prev => ({
      ...prev,
      [matchId]: {
        ...(prev[matchId] || { home: 0, away: 0 }),
        [side]: val
      }
    }));
  };

  const onSettle = async (matchId: string) => {
    const scores = editingScores[matchId] || { home: 0, away: 0 };
    startTransition(async () => {
      try {
        await settleMatchResult(matchId, scores.home, scores.away);
        setSuccessMsg('Match result settled successfully.');
        setTimeout(() => setSuccessMsg(''), 3000);
      } catch (err: any) {
        setErrorMsg(err.message || 'Settlement failed');
      }
    });
  };

  const handleStatusChange = async (matchId: string, status: 'scheduled' | 'live' | 'finished') => {
    startTransition(async () => {
      try {
        await updateMatchStatus(matchId, status);
        setSuccessMsg(`Match marked as ${status}.`);
        setTimeout(() => setSuccessMsg(''), 3000);
      } catch (err: any) {
        setErrorMsg(err.message || 'Status update failed');
      }
    });
  };

  const handleRoundStatusChange = async (roundId: string, status: 'upcoming' | 'active' | 'completed') => {
    startTransition(async () => {
      try {
        await updateRoundStatus(roundId, status);
        setSuccessMsg(`Round status updated to ${status}.`);
        setTimeout(() => setSuccessMsg(''), 3000);
      } catch (err: any) {
        setErrorMsg(err.message || 'Round status update failed');
      }
    });
  };

  const handleCreateMatch = async () => {
    if (!matchData.home_team || !matchData.away_team || !matchData.kickoff_time || !selectedRoundId) return;
    startTransition(async () => {
      try {
        await createMatch({ ...matchData, round_id: selectedRoundId });
        setSuccessMsg('Match added to round successfully.');
        setShowMatchModal(false);
        setMatchData({ home_team: '', away_team: '', kickoff_time: '' });
        setTimeout(() => setSuccessMsg(''), 3000);
      } catch (err: any) {
        setErrorMsg(err.message || 'Creation failed');
      }
    });
  };

  return (
    <>
    <div className="flex flex-col gap-24 animate-slide-up">
      {/* Toast Notifications */}
      {(successMsg || errorMsg) && (
        <div className={`fixed bottom-6 right-6 z-[100] px-5 py-3 rounded-xl backdrop-blur-xl border flex items-center gap-3 shadow-2xl animate-slide-up ${
          successMsg ? 'bg-success/90 border-success/20 text-black' : 'bg-danger/90 border-danger/20 text-white'
        }`}>
           {successMsg ? <Check className="w-4 h-4" /> : <AlertCircle className="w-4 h-4" />}
           <span className="text-xs font-bold">{successMsg || errorMsg}</span>
        </div>
      )}

      {/* ─── ROUNDS OVERVIEW ─── */}
      <div className="card p-6 bg-white/[0.02]">
        <div className="flex justify-between items-center mb-6 px-4">
          <div className="flex items-center gap-10">
             <Calendar className="w-5 h-5 text-blue-electric opacity-60" />
             <h2 className="font-display text-lg font-black uppercase tracking-widest">Platform Rounds</h2>
          </div>
          <button 
            onClick={() => setShowMatchModal(true)}
            disabled={!selectedRoundId}
            className="btn btn-primary btn-xs px-16 h-40 font-black uppercase tracking-widest text-[10px] flex items-center gap-8"
          >
            <Plus className="w-4 h-4" /> ADD MATCH TO ROUND
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          {rounds.map(r => (
            <div 
              key={r.id} 
              onClick={() => setSelectedRoundId(r.id)}
              className={`p-16 rounded-xl border transition-all cursor-pointer group ${
                selectedRoundId === r.id 
                ? 'bg-blue-electric/[0.05] border-blue-electric/40 shadow-lg shadow-blue-electric/5' 
                : 'bg-white/[0.02] border-white/5 hover:border-white/10'
              }`}
            >
              <div className="flex justify-between items-center mb-10">
                <span className={`text-[9px] font-black uppercase tracking-[0.2em] ${selectedRoundId === r.id ? 'text-blue-electric' : 'text-muted'}`}>Round {r.round_number}</span>
                <div className={`w-3 h-3 rounded-full ${r.status === 'active' ? 'bg-success animate-pulse' : r.status === 'completed' ? 'bg-blue-electric' : 'bg-muted opacity-20'}`} />
              </div>
              <div className="text-[10px] text-white font-black font-mono uppercase tracking-tighter">
                 {r.status}
              </div>
              <div className="text-[9px] text-muted font-bold mt-4 opacity-40 font-mono">
                 {new Date(r.start_date).toLocaleDateString()} — Logged
              </div>
            </div>
          ))}
        </div>
      </div>

      {selectedRound && (
        <div className={`card p-6 animate-fade-in relative overflow-hidden group transition-all duration-500 ${
          selectedRound.status === 'active' 
          ? 'border-blue-electric/20 bg-blue-electric/[0.03]' 
          : 'border-danger/30 bg-danger/[0.03] shadow-lg shadow-danger/5'
        }`}>
           <div className="absolute top-0 right-0 p-8 opacity-5 text-blue-electric"><Trophy className="w-12 h-12" /></div>
           <div className="flex justify-between items-center relative z-10">
              <div className="flex items-center gap-12">
                <div className={`p-10 rounded-xl ${selectedRound.status === 'active' ? 'bg-blue-electric/10' : 'bg-danger/20'}`}>
                  <Settings2 className={`w-5 h-5 ${selectedRound.status === 'active' ? 'text-blue-electric' : 'text-danger'}`} />
                </div>
                <div>
                  <div className="flex items-center gap-8">
                    <h3 className="font-black text-sm text-white uppercase tracking-widest">Management: Round {selectedRound.round_number}</h3>
                    {selectedRound.status !== 'active' && (
                      <div className="flex items-center gap-4 px-8 py-2 bg-danger/20 border border-danger/30 rounded-full animate-pulse">
                         <AlertCircle className="w-3 h-3 text-danger" />
                         <span className="text-[8px] font-black text-danger uppercase tracking-widest">Status Warning: Inactive</span>
                      </div>
                    )}
                  </div>
                  <p className="text-[9px] text-muted font-bold uppercase tracking-widest opacity-60 flex items-center gap-6">
                     {selectedRound.status === 'active' ? 'Platform Node: Synchronized' : 'Platform Node: Offline/Upcoming'} <ChevronRight className="w-3 h-3" /> Management Mode
                  </p>
                </div>
              </div>
              <div className="flex gap-8">
                 <button 
                  disabled={isPending || selectedRound.status === 'active'}
                  onClick={() => handleRoundStatusChange(selectedRound.id, 'active')}
                  className={`btn btn-xs px-16 py-8 font-black uppercase text-[9px] tracking-widest ${selectedRound.status === 'active' ? 'bg-success/20 text-success border-success/30' : 'btn-primary shadow-lg shadow-gold/20 animate-bounce-subtle'}`}
                 >{selectedRound.status === 'active' ? 'Active' : 'ACTIVATE ROUND NOW'}</button>
                 <button 
                  disabled={isPending || selectedRound.status === 'completed'}
                  onClick={() => handleRoundStatusChange(selectedRound.id, 'completed')}
                  className={`btn btn-xs px-16 py-8 font-black uppercase text-[9px] tracking-widest ${selectedRound.status === 'completed' ? 'bg-blue-electric text-white border-blue-electric/40 shadow-lg shadow-blue-electric/20' : 'btn-ghost border-dashed opacity-40 hover:opacity-100'}`}
                 >Settle Round</button>
              </div>
           </div>
        </div>
      )}

      {/* ─── MATCH SETTLEMENT GRID ─── */}
      <div className="card p-6 bg-white/[0.02]">
        <div className="flex justify-between items-center mb-6 px-4">
          <div className="flex items-center gap-10">
             <Trophy className="w-5 h-5 text-gold opacity-60" />
             <h2 className="font-display text-lg font-black uppercase tracking-widest text-white">Match Management</h2>
          </div>
        </div>
        
        <div className="flex flex-col gap-6">
          {filteredMatches.length === 0 ? (
            <div className="py-60 text-center flex flex-col items-center gap-4 opacity-30">
               <Sword className="w-10 h-10 text-muted" />
               <p className="text-[10px] text-muted font-black uppercase tracking-widest font-mono italic">No matches scheduled in this round.</p>
            </div>
          ) : (
            filteredMatches.map(m => (
              <div key={m.id} className={`card p-16 transition-all border outline-none ${
                  m.status === 'live' 
                  ? 'border-danger/30 bg-danger/[0.03] shadow-lg shadow-danger/5' 
                  : 'border-white/5 bg-white/[0.02] hover:border-white/10'
                }`}
              >
                <div className="flex justify-between items-center gap-24 flex-wrap md:flex-nowrap">
                  <div className="min-w-[120px]">
                    <div className="flex items-center gap-8 mb-2">
                       <div className={`w-3 h-3 rounded-full ${m.status === 'live' ? 'bg-danger animate-pulse shadow-[0_0_6px_var(--danger)]' : 'bg-muted opacity-40'}`} />
                       <div className={`text-[9px] font-black uppercase tracking-[0.2em] ${m.status === 'live' ? 'text-danger' : 'text-muted'}`}>
                         {m.status === 'live' ? 'LIVE NOW' : m.status}
                       </div>
                    </div>
                    <div className="text-[10px] text-muted font-black font-mono uppercase tracking-tighter opacity-60 flex items-center gap-6">
                       <Activity className="w-3.5 h-3.5" /> {new Date(m.kickoff_time).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </div>
                  </div>

                  <div className="flex-1 flex items-center gap-16 md:gap-24 min-w-[250px] justify-center">
                    <div className="flex-1 text-right font-display text-base font-black tracking-tight text-white uppercase italic truncate">
                       {m.home_team}
                    </div>
                    
                    <div className="flex items-center gap-4 bg-black/40 p-4 rounded-xl border border-white/10">
                        <input 
                          type="number" 
                          disabled={m.status === 'finished'}
                          value={editingScores[m.id]?.home ?? m.home_score ?? 0} 
                          onChange={(e) => handleScoreChange(m.id, 'home', Number(e.target.value))}
                          className="w-10 h-10 bg-white/5 border border-white/10 rounded-lg text-center text-sm font-black font-display text-white focus:outline-none focus:border-blue-electric transition-colors [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                        />
                        <div className="flex flex-col items-center opacity-20 ml-2 mr-2">
                           <span className="text-[8px] font-black uppercase tracking-tighter">VS</span>
                        </div>
                        <input 
                          type="number" 
                          disabled={m.status === 'finished'}
                          value={editingScores[m.id]?.away ?? m.away_score ?? 0} 
                          onChange={(e) => handleScoreChange(m.id, 'away', Number(e.target.value))}
                          className="w-10 h-10 bg-white/5 border border-white/10 rounded-lg text-center text-sm font-black font-display text-white focus:outline-none focus:border-blue-electric transition-colors [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                        />
                    </div>
                    
                    <div className="flex-1 text-left font-display text-base font-black tracking-tight text-white uppercase italic truncate">
                       {m.away_team}
                    </div>
                  </div>

                  <div className="flex flex-col gap-4 min-w-[180px]">
                    {m.status !== 'finished' ? (
                      <>
                        <button 
                          disabled={isPending}
                          onClick={() => onSettle(m.id)}
                          className="btn btn-blue w-full py-10 font-black uppercase text-[10px] tracking-widest shadow-lg shadow-blue-electric/20 flex items-center justify-center gap-8"
                        >
                           <ShieldCheck className="w-4 h-4" />
                           {isPending ? 'SAVING...' : 'SAVE RESULT'}
                        </button>
                        <div className="flex gap-4 mt-1">
                           <button 
                            disabled={isPending || m.status === 'live'}
                            onClick={() => handleStatusChange(m.id, 'live')}
                            className="bg-white/5 hover:bg-danger/10 text-muted hover:text-danger border border-white/5 hover:border-danger/20 p-8 rounded-lg flex-1 text-[8px] font-black uppercase tracking-widest transition-all flex items-center justify-center gap-4 group"
                           >
                              <Play className="w-3 h-3 group-hover:fill-danger" /> GO LIVE
                           </button>
                           <button 
                            disabled={isPending || m.status === 'scheduled'}
                            onClick={() => handleStatusChange(m.id, 'scheduled')}
                            className="bg-white/5 hover:bg-white/10 border border-white/5 p-8 rounded-lg flex-1 text-[8px] font-black uppercase tracking-widest transition-all flex items-center justify-center gap-4"
                           >
                              <RotateCcw className="w-3 h-3 opacity-40" /> RESET
                           </button>
                        </div>
                      </>
                    ) : (
                      <div className="flex flex-col gap-4">
                         <div className="flex items-center justify-center gap-8 py-10 rounded-xl bg-success/10 border border-success/30 text-success text-[10px] font-black uppercase tracking-widest shadow-lg shadow-success/10">
                            <CheckCircle2 className="w-4 h-4 font-black" /> Finalized
                         </div>
                         <button 
                          disabled={isPending}
                          onClick={() => handleStatusChange(m.id, 'scheduled')}
                          className="text-[8px] text-muted hover:text-white transition-colors underline uppercase font-black tracking-widest mt-4 opacity-40 text-center"
                         >Undo Settlement</button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>

    {/* ADD MATCH MODAL */}
    {showMatchModal && (
      <div className="fixed inset-0 z-[100] flex items-center justify-center p-24">
        <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => !isPending && setShowMatchModal(false)} />
        <div className="card w-full max-w-[440px] p-0 relative z-10 animate-slide-up bg-zinc-950 border-white/10">
           <div className="p-24 border-b border-white/5 flex justify-between items-center bg-white/[0.01]">
              <div className="flex items-center gap-12">
                 <div className="p-10 bg-blue-electric/10 rounded-xl"><Plus className="w-5 h-5 text-blue-electric" /></div>
                 <div>
                    <h3 className="font-display font-black text-white uppercase tracking-widest leading-none">Schedule Match</h3>
                    <p className="text-[9px] text-muted font-bold uppercase tracking-widest mt-4 opacity-60">Round {selectedRound?.round_number} Assignment</p>
                 </div>
              </div>
           </div>
           
           <div className="p-24 flex flex-col gap-20">
              <div className="grid grid-cols-2 gap-12">
                 <div className="flex flex-col gap-6">
                    <label className="text-[9px] font-black text-muted uppercase tracking-widest ml-4">Home Team</label>
                    <input 
                      type="text" 
                      value={matchData.home_team} 
                      onChange={e => setMatchData(prev => ({ ...prev, home_team: e.target.value }))}
                      className="input-premium py-12 text-xs font-bold" 
                      placeholder="e.g. Arsenal" 
                    />
                 </div>
                 <div className="flex flex-col gap-6">
                    <label className="text-[9px] font-black text-muted uppercase tracking-widest ml-4">Away Team</label>
                    <input 
                      type="text" 
                      value={matchData.away_team} 
                      onChange={e => setMatchData(prev => ({ ...prev, away_team: e.target.value }))}
                      className="input-premium py-12 text-xs font-bold" 
                      placeholder="e.g. Chelsea" 
                    />
                 </div>
              </div>

              <div className="flex flex-col gap-6">
                 <label className="text-[9px] font-black text-muted uppercase tracking-widest ml-4">Kickoff Time</label>
                 <input 
                   type="datetime-local" 
                   value={matchData.kickoff_time} 
                   onChange={e => setMatchData(prev => ({ ...prev, kickoff_time: e.target.value }))}
                   className="input-premium py-12 text-xs font-mono" 
                 />
              </div>

              <div className="p-12 bg-blue-electric/5 border border-blue-electric/10 rounded-xl flex items-center gap-12 mt-8">
                 <AlertCircle className="w-5 h-5 text-blue-electric opacity-40" />
                 <p className="text-[9px] text-muted leading-relaxed font-bold uppercase tracking-tight">Predictions will open immediately upon scheduling unless the kickoff time has passed.</p>
              </div>
           </div>

           <div className="p-24 border-t border-white/5 flex gap-12 bg-white/[0.01]">
              <button 
                onClick={() => setShowMatchModal(false)}
                className="btn btn-ghost flex-1 py-12 font-black uppercase text-[10px] tracking-widest opacity-60 hover:opacity-100"
              >Cancel</button>
              <button 
                onClick={handleCreateMatch}
                disabled={isPending || !matchData.home_team || !matchData.away_team || !matchData.kickoff_time}
                className="btn btn-blue flex-1 py-12 font-black uppercase text-[10px] tracking-widest shadow-xl shadow-blue-electric/20"
              >
                {isPending ? 'SCHEDULING...' : 'CONFIRM MATCH'}
              </button>
           </div>
        </div>
      </div>
    )}
    </>
  );
}

'use client';

import { useState, useEffect, useTransition } from 'react';
import { 
  Settings, 
  ShieldAlert, 
  DollarSign, 
  Megaphone, 
  BarChart3, 
  Database, 
  RefreshCcw, 
  Power, 
  Globe, 
  Activity, 
  Check,
  ChevronRight,
  ShieldCheck,
  Zap
} from 'lucide-react';
import { updatePlatformSettings, getAllPlatformSettings, revalidatePlatform } from '@/app/actions/admin';
import { PlatformSettings } from '@/types';
import { useFeedback } from '@/hooks/useFeedback';

export default function SettingsView() {
  const [isPending, startTransition] = useTransition();
  const { success: successMsg, showSuccess } = useFeedback();
  const [settings, setSettings] = useState<PlatformSettings>({
    maintenance_mode: false,
    referral_bonus: 1000,
    announcement_banner: { text: '', active: false },
    trust_stats_mode: 'real',
    tier_pricing: { starter: 5000, standard: 10000, premium: 25000 }
  });

  useEffect(() => {
    const loadSettings = async () => {
      const data = await getAllPlatformSettings();
      if (data) {
        setSettings((prev) => ({ ...prev, ...(data as Partial<PlatformSettings>) }));
      }
    };
    loadSettings();
  }, []);

  const handleUpdate = async <K extends keyof PlatformSettings>(key: K, value: PlatformSettings[K]) => {
    startTransition(async () => {
      try {
        await updatePlatformSettings(key, value);
        setSettings((prev) => ({ ...prev, [key]: value }));
        showSuccess(`Setting updated successfully.`);
      } catch (err) {
        console.error('Update failed:', err);
      }
    });
  };
  const handleRevalidate = async () => {
    startTransition(async () => {
      try {
        await revalidatePlatform();
        showSuccess('Platform cache revalidated.');
      } catch (err) {
        console.error('Revalidation failed:', err);
      }
    });
  };

  return (
    <div className="flex flex-col gap-24 animate-slide-up">
      {/* Toast Notifications */}
      {successMsg && (
        <div className="fixed bottom-24 right-24 z-[100] px-20 py-12 bg-success/90 backdrop-blur-xl border border-success/20 text-black rounded-xl flex items-center gap-12 shadow-2xl animate-slide-up">
           <Check className="w-16 h-16" />
           <span className="text-xs font-bold">{successMsg}</span>
        </div>
      )}

      {/* ─── SETTINGS HEADER ─── */}
      <div className="card p-4 flex justify-between items-center gap-6">
        <div className="flex items-center gap-2">
           <div className="p-2 bg-blue-electric/10 rounded-lg"><Settings className="w-5 h-5 text-blue-electric" /></div>
           <div>
              <h2 className="font-display text-lg font-black tracking-tight">Platform Settings</h2>
              <p className="text-[9px] text-muted font-bold uppercase tracking-widest opacity-60">Global App Configuration</p>
           </div>
        </div>
        <div className="badge badge-muted text-[8px] font-black uppercase px-2 py-1 border border-white/10">Active Session</div>
      </div>
        
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-24 items-start">
        <div className="flex flex-col gap-24">
          <div className="card p-24 bg-white/[0.02]">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-muted mb-20 flex items-center gap-8">
               <Power className="w-5 h-5" /> Access Control
            </h3>
            
            <div className="flex flex-col gap-10">
              {/* Maintenance Mode */}
              <div className="flex justify-between items-center p-16 bg-white/[0.03] rounded-xl border border-white/5 group hover:border-white/10 transition-all">
                <div className="flex items-center gap-12">
                   <div className={`w-8 h-8 rounded-full ${settings.maintenance_mode ? 'bg-danger shadow-[0_0_8px_var(--danger)] animate-pulse' : 'bg-success shadow-[0_0_8px_var(--success)]'}`} />
                   <div>
                     <div className="font-black text-xs text-white">Maintenance Mode</div>
                     <div className="text-[9px] text-muted font-bold uppercase tracking-widest opacity-40">Block non-admin ingress</div>
                   </div>
                </div>
                <button 
                  onClick={() => handleUpdate('maintenance_mode', !settings.maintenance_mode)}
                  disabled={isPending}
                  className={`btn btn-xs px-16 py-8 font-black uppercase text-[9px] tracking-widest transition-all ${settings.maintenance_mode ? 'bg-danger text-white border-danger/30' : 'bg-white/5 text-muted hover:text-white border-dashed'}`}
                >
                  {settings.maintenance_mode ? 'ACTIVE' : 'OFF'}
                </button>
              </div>

              {/* Referral Bonus */}
              <div className="flex justify-between items-center p-16 bg-white/[0.03] rounded-xl border border-white/5 group hover:border-white/10 transition-all">
                <div className="flex items-center gap-12">
                   <div className="p-8 bg-blue-electric/10 rounded-lg"><DollarSign className="w-5 h-5 text-blue-electric" /></div>
                   <div>
                     <div className="font-black text-xs text-white">Referral Bonus</div>
                     <div className="text-[9px] text-muted font-bold uppercase tracking-widest opacity-40">NGN Reward per Conversion</div>
                   </div>
                </div>
                <div className="flex gap-8 items-center">
                    <input 
                        type="number" 
                        value={settings.referral_bonus} 
                        onChange={(e) => setSettings((prev) => ({ ...prev, referral_bonus: Number(e.target.value) }))}
                        className="w-24 h-10 bg-black/40 border border-white/10 text-white rounded-lg px-8 text-[11px] font-black focus:outline-none focus:border-blue-electric"
                    />
                    <button 
                      onClick={() => handleUpdate('referral_bonus', settings.referral_bonus)} 
                      disabled={isPending}
                      className="p-8 bg-blue-electric/10 hover:bg-blue-electric/20 text-blue-electric rounded-lg transition-all"
                    >
                      <Check className="w-4 h-4" />
                    </button>
                </div>
              </div>

              {/* Trust Stats Mode */}
              <div className="p-16 bg-white/[0.03] rounded-xl border border-white/5 group hover:border-white/10 transition-all">
                <div className="flex items-center gap-12 mb-16">
                   <div className="p-8 bg-blue-electric/10 rounded-lg"><BarChart3 className="w-5 h-5 text-blue-electric" /></div>
                   <div>
                     <div className="font-black text-xs text-white">Stats Mode</div>
                     <div className="text-[9px] text-muted font-bold uppercase tracking-widest opacity-40">Display mode for metrics</div>
                   </div>
                </div>
                <div className="grid grid-3 gap-4">
                    {['real', 'launch', 'hidden'].map(m => (
                        <button 
                            key={m}
                            disabled={isPending}
                            onClick={() => handleUpdate('trust_stats_mode', m as 'real' | 'launch' | 'hidden')}
                            className={`py-8 text-[9px] font-black uppercase tracking-widest rounded-lg border transition-all ${
                                settings.trust_stats_mode === m 
                                ? 'bg-blue-electric/[0.05] border-blue-electric/40 text-blue-electric' 
                                : 'bg-transparent border-dashed border-white/10 text-muted opacity-40 hover:opacity-100'
                            }`}
                        >
                            {m}
                        </button>
                    ))}
                </div>
              </div>
            </div>
          </div>

          {/* Announcement Banner */}
          <div className="card p-24 bg-white/[0.02]">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-muted mb-20 flex items-center gap-8">
               <Megaphone className="w-4 h-4" /> Announcement Banner
            </h3>
            <div className="flex flex-col gap-12">
              <textarea 
                  value={settings.announcement_banner?.text || ''} 
                  onChange={(e) => setSettings((prev) => ({ ...prev, announcement_banner: { ...prev.announcement_banner, text: e.target.value } }))}
                  className="input-premium flex-1 h-24 text-xs font-medium py-12" 
                  placeholder="Banner notification text..."
              />
              <div className="flex gap-4">
                <button 
                  onClick={() => handleUpdate('announcement_banner', { ...settings.announcement_banner, active: !settings.announcement_banner?.active })} 
                  className={`flex-1 py-10 rounded-xl border font-black uppercase text-[10px] tracking-widest transition-all ${
                    settings.announcement_banner?.active 
                    ? 'bg-blue-electric/20 text-blue-electric border-blue-electric/30' 
                    : 'bg-white/5 text-muted border-dashed border-white/10 opacity-40 hover:opacity-100'
                  }`}
                >
                  {settings.announcement_banner?.active ? 'Active' : 'Inactive'}
                </button>
                <button 
                  onClick={() => handleUpdate('announcement_banner', settings.announcement_banner)} 
                  disabled={isPending}
                  className="btn btn-blue px-24 py-10 font-black uppercase text-[10px] tracking-widest shadow-lg shadow-blue-electric/20"
                >Update Banner</button>
              </div>
            </div>
          </div>
        </div>

        <div className="flex flex-col gap-24">
          {/* Tier Pricing */}
          <div className="card p-24 bg-white/[0.02]">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-muted mb-20 flex items-center gap-8">
               <Globe className="w-5 h-5" /> Pricing Structure
            </h3>
            <div className="flex flex-col gap-10">
               {Object.entries(settings.tier_pricing || {}).map(([tier, price]) => (
                <div key={tier} className="flex justify-between items-center p-12 bg-white/[0.03] border border-white/5 rounded-xl group hover:border-white/10 transition-all">
                   <div className="flex items-center gap-12">
                      <div className="w-8 h-8 rounded-full bg-blue-electric/40" />
                      <span className="text-[11px] font-black text-white uppercase tracking-widest">{tier}</span>
                   </div>
                   <div className="flex items-center gap-10">
                      <span className="text-[10px] text-muted font-bold font-mono">₦</span>
                      <input 
                        type="number" 
                        value={price}
                        onChange={(e) => setSettings((prev) => ({ 
                          ...prev, 
                          tier_pricing: { ...prev.tier_pricing, [tier]: Number(e.target.value) } 
                        }))}
                        className="w-24 h-10 bg-black/40 border border-white/5 text-white rounded-lg px-8 text-[11px] font-black focus:outline-none focus:border-blue-electric text-right"
                      />
                   </div>
                </div>
              ))}
              <button 
                  onClick={() => handleUpdate('tier_pricing', settings.tier_pricing)}
                  disabled={isPending}
                  className="btn btn-blue w-full py-12 mt-10 font-black uppercase text-[10px] tracking-widest shadow-lg shadow-blue-electric/20 flex items-center justify-center gap-8"
              >
                <RefreshCcw className="w-4 h-4" />
                Update All Prices
              </button>
            </div>
          </div>

          {/* SYSTEM TOOLS */}
          <div className="card p-24 bg-danger/[0.02] border-danger/20">
            <div className="flex items-center gap-12 mb-16">
               <div className="p-10 bg-danger/10 rounded-xl"><ShieldAlert className="w-5 h-5 text-danger" /></div>
               <div>
                  <h3 className="font-black text-xs text-white uppercase tracking-widest">System Actions</h3>
                  <p className="text-[9px] text-muted font-bold uppercase tracking-widest opacity-60">High-Risk Tools</p>
               </div>
            </div>
            <p className="text-[10px] text-muted mb-20 leading-relaxed italic opacity-80">Manual actions for debugging and cache updates. Use with caution.</p>
            <div className="flex gap-4">
                <button 
                  onClick={handleRevalidate}
                  disabled={isPending}
                  className="btn btn-danger flex-1 py-12 font-black uppercase text-[10px] tracking-[0.15em] shadow-lg shadow-danger/20 flex items-center justify-center gap-8 group"
                >
                   <Zap className={`w-12 h-12 ${isPending ? 'animate-spin' : 'group-hover:animate-pulse'}`} /> 
                   {isPending ? 'REVALIDATING...' : 'CLEAN CACHE'}
                </button>
                <button className="p-12 hover:bg-white/5 rounded-xl opacity-40 hover:opacity-100 transition-all border border-transparent hover:border-white/10" onClick={() => window.location.reload()}>
                   <RefreshCcw className="w-14 h-14" />
                </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

