import { createClient } from '@/lib/supabase/server';
import { verifyPayment } from '@/app/actions/paystack';
import { redirect } from 'next/navigation';
import { NextRequest } from 'next/server';

export async function GET(request: NextRequest) {
  const searchParams = request.nextUrl.searchParams;
  const reference = searchParams.get('reference');

  if (!reference) {
    redirect('/dashboard?error=Missing payment reference');
  }

  try {
    const result = await verifyPayment(reference);
    
    if (result.success) {
      redirect('/dashboard?success=Payment verified successfully');
    } else {
      redirect(`/dashboard?error=${encodeURIComponent(result.message || 'Verification failed')}`);
    }
  } catch (err: any) {
    console.error('Payment callback error:', err);
    redirect(`/dashboard?error=${encodeURIComponent(err.message || 'Internal payment error')}`);
  }
}

import { NextResponse } from 'next/server';
import crypto from 'crypto';
import { createClient } from '@/lib/supabase/server';
import { verifyPayment } from '@/app/actions/paystack';

const PAYSTACK_SECRET_KEY = process.env.PAYSTACK_SECRET_KEY;

export async function POST(req: Request) {
  const body = await req.text();
  const signature = req.headers.get('x-paystack-signature');

  if (!signature || !PAYSTACK_SECRET_KEY) {
    return new Response('Unauthorized', { status: 401 });
  }

  // 1. Verify Paystack Signature
  const hash = crypto
    .createHmac('sha512', PAYSTACK_SECRET_KEY)
    .update(body)
    .digest('hex');

  if (hash !== signature) {
    return new Response('Unauthorized', { status: 401 });
  }

  const event = JSON.parse(body);

  // 2. Handle successful charge
  if (event.event === 'charge.success') {
    const reference = event.data.reference;

    // We reuse the verifyPayment server action logic for consistency
    // It handles idempotency and tier validation
    try {
      const result = await verifyPayment(reference);
      if (result.success) {
        console.log(`Webhook processed successfully for ref: ${reference}`);
      } else {
        console.error(`Webhook failed for ref: ${reference}`, result.message);
      }
    } catch (err) {
      console.error('Webhook error:', err);
    }
  }

  return NextResponse.json({ status: 'ok' });
}

import { createClient } from '@/lib/supabase/server'
import ArenaClient from '@/components/arena/ArenaClient'
import Navbar from '@/components/Navbar'
import Footer from '@/components/Footer'

export default async function ArenaPage() {
  const supabase = await createClient()

  // Fetch active round data
  const { data: activeRound } = await supabase
    .from('challenge_rounds')
    .select('*')
    .eq('status', 'active')
    .single()

  // Fetch matches for the active round
  const { data: matches } = await supabase
    .from('challenge_matches')
    .select('*')
    .eq('round_id', activeRound?.id)
    .order('kickoff_time', { ascending: true })

  // Fetch global stats for social proof
  const { count: activePlayers } = await supabase
    .from('profiles')
    .select('*', { count: 'exact', head: true })
    .eq('status', 'active')

  return (
    <ArenaClient 
      activeRound={activeRound} 
      matches={matches || []} 
      stats={{ activePlayers: activePlayers || 0 }} 
    />
  )
}

