                  return (
                    <div key={m.id} className={`card p-0 overflow-hidden transition-all duration-500 hover:border-white/10 ${isLocked ? 'grayscale-[0.5] opacity-90' : 'animate-slide-up shadow-xl shadow-black/20'}`}>
