import styles from './Navbar.module.css';

const navLinks = [
  { href: '/', label: 'HOME' },
  { href: '/how-it-works', label: 'HOW IT WORKS' },
  { href: '/accounts', label: 'ACCOUNTS' },
  { href: '/live-challenges', label: 'CHALLENGES' },
